	int n,pen1,a,pen2,b,pen3,c,e=0,f=0,g=0,min,i;
	cin>>n>>pen1>>a>>pen2>>b>>pen3>>c;
	while(e*pen1<n) e+=1;
	while(f*pen2<n) f+=1;
	while(g*pen3<n) g+=1;
	min=e*a;
	if(min>f*b){
		min=f*b;
	}
	if(min>g*c){
		min=g*c;
	}
	cout<<min;
}
